      "lean_file_body": "theorem IsInverse.unique {L : Type u} [CommRing L] {a b c : L} (h₁ : IsInverse a b) (h₂ : IsInverse a c) : b = c :=\nby\n  have hb : a * b = 1 := h₁\n  have hc : a * c = 1 := h₂\n  calc\n    b = b * 1 := by simp\n    _ = b * (a * c) := by rw [hc]\n    _ = (b * a) * c := by ring\n    _ = (a * b) * c := by rw [mul_comm b a]\n    _ = 1 * c := by rw [hb]\n    _ = c := by simp",
